const { regular, bold } = await loadFonts();
  const { name, address, socialMedia } = brandData;
  const scale = getScale(width, height);

  const cardWidth = width - (80 * scale);
  const cardHeight = 160 * scale; // Adjust based on content
  const cardX = 40 * scale;
  const cardY = height - cardHeight - (40 * scale);
  const borderRadius = 24 * scale;

  // 1. Card Background (White with high alpha)
  const paint = Skia.Paint();
  paint.setColor(Skia.Color('white'));
  paint.setAlphaf(0.92);
  // Shadow simulation (simple dark rect offset)
  const shadowPaint = Skia.Paint();
  shadowPaint.setColor(Skia.Color('black'));
  shadowPaint.setAlphaf(0.2);
  canvas.drawRRect(Skia.RRectXY({x: cardX + 4, y: cardY + 8, width: cardWidth, height: cardHeight}, borderRadius, borderRadius), shadowPaint);

  // Main Card
  canvas.drawRRect(Skia.RRectXY({x: cardX, y: cardY, width: cardWidth, height: cardHeight}, borderRadius, borderRadius), paint);

  // 2. Content
  paint.setColor(Skia.Color('#1a1a1a')); // Almost Black
  paint.setAlphaf(1);

  // Name
  // Inter Bold for modern look
  const titleFont = regular; // Inter Variable Regular is actually quite nice, but let's see if we have bold.
  // variable fonts usually need settings for weight, but for now we rely on the loaded instance.
  // regular is Inter.
  titleFont.setSize(42 * scale);

  // Hack: Fake bold by drawing stroke (not ideal but works for now if variable weight API isn't used)
  // Or just use the 'bold' (Lexend) if Inter looks too thin.
  // Ideally we use Inter for everything. Let's stick to Regular Inter for a clean look.
  drawTextLeft(canvas, name, cardX + (40 * scale), cardY + (60 * scale), titleFont, paint, cardWidth - (60 * scale));

  // Secondary Info (Address or Social)
  const bodyFont = regular;
  bodyFont.setSize(26 * scale);
  paint.setColor(Skia.Color('#555555'));

  let secondaryText = address || "";
  if (socialMedia?.instagram) {
      secondaryText = `@${socialMedia.instagram}`;
      if (address) secondaryText += ` • ${address}`;
  }

  if (secondaryText) {
      // Truncate if too long (simple check)
      drawTextLeft(canvas, secondaryText, cardX + (40 * scale), cardY + (110 * scale), bodyFont, paint, cardWidth - (60 * scale));
  }

  // Accent Line on left
  paint.setColor(Skia.Color('#007AFF')); // Modern Blue
  const accentRect = Skia.RRectXY({x: cardX + (12 * scale), y: cardY + (20 * scale), width: 6 * scale, height: cardHeight - (40 * scale)}, 4, 4);
  canvas.drawRRect(accentRect, paint);

  //RETURN REQUIRED BRAND INFO
  return ["name", "address", "socialMedia"];

const { regular, condensed } = await loadFonts();
  const { name, website } = brandData;
  const scale = getScale(width, height);

  const paint = Skia.Paint();

  // Angled Tech Accent
  paint.setColor(Skia.Color('#6366f1')); // Indigo
  const path = Skia.Path.Make();
  path.moveTo(0, height - 120*scale);
  path.lineTo(width * 0.3, height - 120*scale);
  path.lineTo(width * 0.35, height);
  path.lineTo(0, height);
  path.close();
  canvas.drawPath(path, paint);

  // Bottom Bar
  paint.setColor(Skia.Color('#0f172a')); // Slate 900
  canvas.drawRect({ x: width * 0.35, y: height - 60*scale, width: width * 0.65, height: 60*scale }, paint);

  // Text
  paint.setColor(Skia.Color('white'));
  const nFont = condensed;
  nFont.setSize(35 * scale);
  drawTextLeft(canvas, name.toUpperCase(), 40 * scale, height - 45 * scale, nFont, paint, width - (40 * scale));

  if (website) {
    const wFont = regular;
    wFont.setSize(22 * scale);
    drawTextLeft(canvas, website, width - wFont.getTextWidth(website) - 40*scale, height - 22*scale, wFont, paint, width - (40 * scale));
  }

  return ["name", "website"];

const { regular, icons } = await loadFonts();
  const { name, address, socialMedia } = brandData;
  const scale = getScale(width, height);

  const paint = Skia.Paint();
  paint.setColor(Skia.Color('rgba(255, 255, 255, 0.9)'));

  // 1. Address Pill (Bottom Left)
  if (address) {
    const addrFont = regular;
    addrFont.setSize(24 * scale);
    const textW = addrFont.getTextWidth(address);
    const pillW = textW + (100 * scale);

    canvas.drawRRect(Skia.RRectXY({x: 30*scale, y: height - 180*scale, width: pillW, height: 60*scale}, 30*scale, 30*scale), paint);

    paint.setColor(Skia.Color('black'));
    drawIcon(canvas, 'pin', 50*scale, height - 165*scale, 24*scale, paint, icons);
    drawTextLeft(canvas, address, 90*scale, height - 140*scale, addrFont, paint, width - (40 * scale));
  }

  // 2. Instagram Pill (Just above Address)
  if (socialMedia?.instagram) {
    paint.setColor(Skia.Color('rgba(255, 255, 255, 0.9)'));
    const handle = `@${socialMedia.instagram}`;
    const font = regular;
    font.setSize(24 * scale);
    const textW = font.getTextWidth(handle);
    const pillW = textW + (100 * scale);

    canvas.drawRRect(Skia.RRectXY({x: 30*scale, y: height - 260*scale, width: pillW, height: 60*scale}, 30*scale, 30*scale), paint);

    paint.setColor(Skia.Color('black'));
    drawIcon(canvas, 'logo-instagram', 50*scale, height - 245*scale, 24*scale, paint, icons);
    drawTextLeft(canvas, handle, 90*scale, height - 220*scale, font, paint, width - (40 * scale));
  }

  return ["address", "socialMedia"];
